  const url = process.env.KV_REST_API_URL;
  const token = process.env.KV_REST_API_TOKEN;

  if (!url || !token) {
    return;
  }

  const response = await fetch(`${url}/set/${encodeURIComponent(STORE_KEY)}`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(value),
  });

  if (!response.ok) {
    throw new Error(`KV SET failed with ${response.status}`);
  }
}

async function readState() {
  if (memory.state) {
    return memory.state;
  }

  try {
    const fromKv = await getKvValue();
    memory.state = parseState(fromKv);
  } catch (error) {
    memory.state = createEmptyState();
  }

  return memory.state;
}

async function writeState(nextState) {
  const state = parseState(nextState);
  state.updatedAt = nowMs();
  memory.state = state;

  try {
    await setKvValue(state);
  } catch (error) {
    // Keep in-memory state even when persistent storage is unavailable.
  }

  return state;
}

async function withState(mutator) {
  const current = await readState();
  const draft = parseState(current);
  const result = await mutator(draft);
  const saved = await writeState(draft);
  return { state: saved, result };
}

function normalizePlayerId(player) {
  const uuid = String(player?.uuid || '').trim();
  const name = String(player?.name || player?.username || '').trim();
  return uuid || name.toLowerCase();
}

function ensurePlayerRecord(players, player, timestamp) {
  const id = normalizePlayerId(player);

  if (!id) {
    return null;
  }

  const existing = players[id] && typeof players[id] === 'object' ? players[id] : {};
  const dayKey = getDayKey(timestamp);
  const weekKey = getWeekKey(timestamp);

  const record = {
    id,
    uuid: String(player?.uuid || existing.uuid || '').trim(),
    name: String(player?.name || player?.username || existing.name || '').trim(),
    ping: toFiniteNumber(player?.ping, toFiniteNumber(existing.ping, 0)),
    isOnline: Boolean(existing.isOnline),
    isAFK: Boolean(existing.isAFK),
    joinTime: toFiniteNumber(existing.joinTime, 0),
    lastSeen: toFiniteNumber(existing.lastSeen, 0),
    lastActive: toFiniteNumber(existing.lastActive, timestamp),
    lastCalcAt: toFiniteNumber(existing.lastCalcAt, timestamp),
    sessionActiveSeconds: toFiniteNumber(existing.sessionActiveSeconds, 0),
    totalPlaytime: toFiniteNumber(existing.totalPlaytime, 0),
    dailyPlaytime: toFiniteNumber(existing.dailyPlaytime, 0),
    weeklyPlaytime: toFiniteNumber(existing.weeklyPlaytime, 0),
    dayKey: String(existing.dayKey || dayKey),
    weekKey: String(existing.weekKey || weekKey),
    updatedAt: toFiniteNumber(existing.updatedAt, timestamp),
  };

  if (!record.name) {
    record.name = record.uuid || id;
  }

  if (record.dayKey !== dayKey) {
    record.dailyPlaytime = 0;
    record.dayKey = dayKey;
  }

  if (record.weekKey !== weekKey) {
    record.weeklyPlaytime = 0;
    record.weekKey = weekKey;
  }

  players[id] = record;
  return record;
}

function applyActiveDelta(record, timestamp) {
  if (!record.isOnline || record.isAFK || record.lastCalcAt <= 0) {
    record.lastCalcAt = timestamp;
    return 0;
  }

  const deltaSeconds = Math.max(0, (timestamp - record.lastCalcAt) / 1000);

  if (deltaSeconds > 0) {
    record.sessionActiveSeconds += deltaSeconds;
    record.dailyPlaytime += deltaSeconds;
    record.weeklyPlaytime += deltaSeconds;
  }

  record.lastCalcAt = timestamp;
  return deltaSeconds;
}

function attachLiveCounters(record, timestamp) {
  const extraSeconds =
    record.isOnline && !record.isAFK && record.lastCalcAt > 0
      ? Math.max(0, (timestamp - record.lastCalcAt) / 1000)
      : 0;

  const sessionTime = Math.floor(record.sessionActiveSeconds + extraSeconds);
  const totalPlaytime = Math.floor(record.totalPlaytime + sessionTime);
  const dailyPlaytime = Math.floor(record.dailyPlaytime + extraSeconds);
  const weeklyPlaytime = Math.floor(record.weeklyPlaytime + extraSeconds);

  return {
    sessionTime,
    totalPlaytime,
    dailyPlaytime,
    weeklyPlaytime,
  };
}

function normalizeLeaderboardItem(entry) {
  if (!entry || typeof entry !== 'object') {
    return null;
  }

  const username = String(entry.username || entry.name || entry.player || '').trim();
  const uuid = String(entry.uuid || entry.id || '').trim();
  const value = toFiniteNumber(entry.value ?? entry.score ?? entry.amount ?? entry.balance ?? entry.kills ?? entry.earnings, NaN);

  if (!username || !Number.isFinite(value) || value < 0) {
    return null;
  }

  return {
    username,
    uuid,
    value,
  };
}

function normalizeLeaderboardItems(items) {
  if (!Array.isArray(items)) {
    return [];
  }

  return items
    .map(normalizeLeaderboardItem)
    .filter(Boolean)
    .sort((a, b) => b.value - a.value)
    .slice(0, LEADERBOARD_LIMIT);
}

module.exports = {
  AFK_TIMEOUT_MS,
  HISTORY_LIMIT,
  LEADERBOARD_LIMIT,
  createEmptyState,
  readState,
  writeState,
  withState,
  toFiniteNumber,
  nowMs,
  getDayKey,
  getWeekKey,
  normalizePlayerId,
  ensurePlayerRecord,
  applyActiveDelta,
  attachLiveCounters,
  normalizeLeaderboardItems,
  normalizeUuid,
  normalizeUsernameKey,
  buildAvatarUrl,
  buildCrackedAvatarUrl,
  buildFallbackAvatarUrl,
  getCachedIdentity,
  setCachedIdentity,
};

const {
  AFK_TIMEOUT_MS,
  HISTORY_LIMIT,
  applyActiveDelta,
  attachLiveCounters,
  ensurePlayerRecord,
  normalizePlayerId,
  nowMs,
  readState,
  getCachedIdentity,
  setCachedIdentity,
  buildAvatarUrl,
  normalizeUuid,
  toFiniteNumber,
  withState,
} = require('./_state');
const { publishRealtimeEvent } = require('./_realtime');

const MOJANG_PROFILE_URL = 'https://api.mojang.com/users/profiles/minecraft/';
const mojangRequestCache = new Map();

const defaultSnapshot = {
  cpu: 0,
  ram: 0,
  ramUsed: 0,
  ramMax: 0,
  players: 0,
  playerList: [],
  uptime: 0,
  ip: 'dxir.live',
  status: 'offline',
  time: '--',
  lastUpdate: 0,
  ready: false,
};

function setCorsHeaders(res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,POST,OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  res.setHeader('Cache-Control', 'no-store, max-age=0');
}

function normalizeStatus(value) {
  return String(value || 'offline').trim().toLowerCase() === 'online' ? 'online' : 'offline';
}

function normalizeNumber(value, fallback = 0) {
  const parsed = toFiniteNumber(value, fallback);
  return parsed >= 0 ? parsed : fallback;
}

async function resolveUuidFromMojang(username) {
  const key = String(username || '').trim().toLowerCase();
  if (!key) {
    return '';
  }

  if (mojangRequestCache.has(key)) {
    return mojangRequestCache.get(key);
  }

  const pending = (async () => {
    const response = await fetch(`${MOJANG_PROFILE_URL}${encodeURIComponent(key)}`, {
      method: 'GET',
      headers: {
        Accept: 'application/json',
      },
    });

    if (!response.ok) {
      return '';
    }

    const payload = await response.json();
    return normalizeUuid(payload?.id);
  })()
    .catch(() => '')
    .finally(() => {
      mojangRequestCache.delete(key);
    });

  mojangRequestCache.set(key, pending);

  try {
    return await pending;
  } catch (error) {
    return '';
  }
}

function normalizePlayerEntry(value) {
  if (typeof value === 'string') {
    const name = value.trim();
    if (!name) {
      return null;
    }

    return { name, uuid: '', ping: 0, status: 'online' };
  }

  if (!value || typeof value !== 'object') {
    return null;
  }

  const name = String(value.name || value.player || value.username || '').trim();
  const uuid = normalizeUuid(value.uuid || value.id || value.playerUuid);

  if (!name) {
    return null;
  }

  return {
    name,
    uuid,
    ping: normalizeNumber(value.ping ?? value.latency ?? value.ms, 0),
    status: String(value.status || 'online').trim() || 'online',
    lastActive: normalizeNumber(value.lastActive ?? value.activityAt, 0),
    active: Boolean(value.active),
  };
}

function normalizePlayerList(value) {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.map(normalizePlayerEntry).filter(Boolean).slice(0, 32);
}

function normalizePayload(payload = {}) {
  const ramUsed = normalizeNumber(payload.ramUsed, defaultSnapshot.ramUsed);

  return {
    cpu: normalizeNumber(payload.cpu, defaultSnapshot.cpu),
    ram: normalizeNumber(payload.ram, Math.round(ramUsed * 1024)),
    ramUsed,
    ramMax: normalizeNumber(payload.ramMax, defaultSnapshot.ramMax),
    players: normalizeNumber(payload.players, defaultSnapshot.players),
    playerList: normalizePlayerList(payload.playerList),
    uptime: normalizeNumber(payload.uptime, defaultSnapshot.uptime),
    ip: typeof payload.ip === 'string' && payload.ip.trim() ? payload.ip.trim() : defaultSnapshot.ip,
    status: normalizeStatus(payload.status),
    time: typeof payload.time === 'string' && payload.time.trim() ? payload.time.trim() : defaultSnapshot.time,
    ready: true,
  };
}

async function resolvePlayersWithMojangUuid(players, sharedState) {
  if (!Array.isArray(players) || !players.length) {
    return [];
  }

  const resolvedPlayers = await Promise.all(players.map(async (player) => {
    const name = String(player?.name || '').trim();
    if (!name) {
      return player;
    }

    const cachedIdentity = getCachedIdentity(sharedState, name);
    const cachedUuid = normalizeUuid(cachedIdentity?.uuid);

    let mojangUuid = cachedUuid;
    if (!mojangUuid) {
      mojangUuid = await resolveUuidFromMojang(name);
      if (mojangUuid) {
        setCachedIdentity(sharedState, name, mojangUuid);
      }
    }

    const fallbackUuid = normalizeUuid(player.uuid);
    const finalUuid = mojangUuid || fallbackUuid;
    const avatarUrl = finalUuid
      ? buildAvatarUrl(finalUuid, 64)
      : (typeof cachedIdentity?.avatarUrl === 'string' ? cachedIdentity.avatarUrl : '');

    // Debug mapping to verify live UUID source.
    console.log(`[DXIR UUID] ${name} => ${finalUuid || 'missing'}`);

    return {
      ...player,
      uuid: finalUuid,
      avatarUrl,
    };
  }));

  return resolvedPlayers;
}

function cloneSnapshot(snapshot) {
  return {
    ...snapshot,
    playerList: Array.isArray(snapshot.playerList)
      ? snapshot.playerList.map((player) => ({
          name: String(player?.name || '').trim(),
          uuid: String(player?.uuid || player?.id || '').trim(),
          avatarUrl: String(player?.avatarUrl || buildAvatarUrl(player?.uuid, 64) || '').trim(),
          ping: normalizeNumber(player?.ping, 0),
          status: String(player?.status || 'online').trim() || 'online',
          isAFK: Boolean(player?.isAFK),
          sessionTime: normalizeNumber(player?.sessionTime, 0),
          totalPlaytime: normalizeNumber(player?.totalPlaytime, 0),
          dailyPlaytime: normalizeNumber(player?.dailyPlaytime, 0),
          weeklyPlaytime: normalizeNumber(player?.weeklyPlaytime, 0),
        })).filter((player) => Boolean(player.name))
      : [],
  };
}

function enrichPlayersWithStats(players, records, timestamp) {
  return players.map((player) => {
    const id = normalizePlayerId(player);
    const record = id ? records[id] : null;

    if (!record) {
      return {
        ...player,
        isAFK: false,
        sessionTime: 0,
        totalPlaytime: 0,
        dailyPlaytime: 0,
        weeklyPlaytime: 0,
      };
    }

    const counters = attachLiveCounters(record, timestamp);
    return {
      ...player,
      isAFK: Boolean(record.isAFK),
      sessionTime: counters.sessionTime,
      totalPlaytime: counters.totalPlaytime,
      dailyPlaytime: counters.dailyPlaytime,
      weeklyPlaytime: counters.weeklyPlaytime,
    };
  });
}

async function currentData() {
  const state = await readState();
  const timestamp = nowMs();
  const latest = state.latestSnapshot
    ? cloneSnapshot({
        ...state.latestSnapshot,
        playerList: enrichPlayersWithStats(state.latestSnapshot.playerList || [], state.players || {}, timestamp),
      })
    : { ...defaultSnapshot };

  return {
    latest,
    history: Array.isArray(state.history) ? state.history.map(cloneSnapshot) : [],
  };
}

function markOfflinePlayers(playersState, onlineIds, timestamp) {
  Object.values(playersState).forEach((record) => {
    if (!record || !record.id) {
      return;
    }

    if (!onlineIds.has(record.id) && record.isOnline) {
      applyActiveDelta(record, timestamp);
      record.totalPlaytime += record.sessionActiveSeconds;
      record.sessionActiveSeconds = 0;
      record.isOnline = false;
      record.isAFK = false;
      record.joinTime = 0;
      record.lastCalcAt = 0;
      record.ping = 0;
      record.updatedAt = timestamp;
    }
  });
}

function updatePlayerRecords(playersState, players, timestamp) {
  const onlineIds = new Set();

  players.forEach((player) => {
    const record = ensurePlayerRecord(playersState, player, timestamp);

    if (!record) {
      return;
    }

    const id = record.id;
    onlineIds.add(id);

    if (!record.isOnline) {
      record.isOnline = true;
      record.isAFK = false;
      record.joinTime = timestamp;
      record.sessionActiveSeconds = 0;
      record.lastCalcAt = timestamp;
      record.lastActive = player.lastActive > 0 ? player.lastActive : timestamp;
    } else {
      applyActiveDelta(record, timestamp);
    }

    const signaledActivity = player.active || player.lastActive > 0;
    if (signaledActivity) {
      record.lastActive = player.lastActive > 0 ? player.lastActive : timestamp;
      record.isAFK = false;
      record.lastCalcAt = timestamp;
    }

    if (timestamp - record.lastActive >= AFK_TIMEOUT_MS) {
      record.isAFK = true;
    }

    record.uuid = player.uuid || record.uuid;
    record.name = player.name || record.name;
    record.avatarUrl = player.avatarUrl || record.avatarUrl || buildAvatarUrl(player.uuid, 64);
    record.ping = normalizeNumber(player.ping, 0);
    record.lastSeen = timestamp;
    record.updatedAt = timestamp;
  });

  markOfflinePlayers(playersState, onlineIds, timestamp);

  return players.map((player) => {
    const record = playersState[normalizePlayerId(player)];
    if (!record) {
      return player;
    }

    const counters = attachLiveCounters(record, timestamp);
    return {
      ...player,
        avatarUrl: record.avatarUrl || player.avatarUrl || buildAvatarUrl(record.uuid, 64),
      status: record.isOnline ? 'online' : 'offline',
      isAFK: Boolean(record.isAFK),
      sessionTime: counters.sessionTime,
      totalPlaytime: counters.totalPlaytime,
      dailyPlaytime: counters.dailyPlaytime,
      weeklyPlaytime: counters.weeklyPlaytime,
    };
  });
}

async function storeSnapshot(snapshot) {
  const { result } = await withState(async (state) => {
    const timestamp = nowMs();
    const previousPlayers = Array.isArray(state.latestSnapshot?.playerList) ? state.latestSnapshot.playerList : [];
    const previousOnline = new Map(previousPlayers.map((player) => [normalizePlayerId(player), player]));
    const resolvedPlayerList = await resolvePlayersWithMojangUuid(snapshot.playerList || [], state);
    const updatedPlayers = updatePlayerRecords(state.players, resolvedPlayerList, timestamp);
    const stampedSnapshot = {
      ...snapshot,
      playerList: updatedPlayers,
      lastUpdate: timestamp,
    };

    state.latestSnapshot = stampedSnapshot;
    state.history = [...(Array.isArray(state.history) ? state.history : []), stampedSnapshot].slice(-HISTORY_LIMIT);

    const currentOnline = new Map(
      updatedPlayers
        .filter((player) => String(player.status || '').toLowerCase() !== 'offline')
        .map((player) => [normalizePlayerId(player), player])
    );

    const joinedPlayers = [];
    const leftPlayers = [];

    currentOnline.forEach((player, id) => {
      if (!previousOnline.has(id)) {
        joinedPlayers.push(player);
      }
    });

    previousOnline.forEach((player, id) => {
      if (!currentOnline.has(id)) {
        leftPlayers.push(player);
      }
    });

    const playtimeRows = Object.values(state.players || {})
      .map((record) => {
        if (!record || !record.id) {
          return null;
        }

        const counters = attachLiveCounters(record, timestamp);
        return {
          username: record.name || record.uuid || record.id,
          uuid: record.uuid || '',
          value: counters.totalPlaytime,
        };
      })
      .filter(Boolean)
      .sort((a, b) => b.value - a.value)
      .slice(0, 10);

    if (!state.leaderboards || typeof state.leaderboards !== 'object') {
      state.leaderboards = {};
    }

    state.leaderboards.playtime = {
      items: playtimeRows,
      updatedAt: timestamp,
    };

    return {
      snapshot: stampedSnapshot,
      joinedPlayers,
      leftPlayers,
      playtimeRows,
      timestamp,
    };
  });

  if (!result) {
    return;
  }

  await publishRealtimeEvent('stats_update', {
    latest: result.snapshot,
  });

  await publishRealtimeEvent('leaderboard_update', {
    category: 'playtime',
    updatedAt: result.timestamp,
    items: result.playtimeRows,
  });

  for (const player of result.joinedPlayers) {
    await publishRealtimeEvent('player_join', {
      uuid: player.uuid || '',
      username: player.name || '',
      playtime: Number(player.totalPlaytime || 0),
      ping: Number(player.ping || 0),
      isAFK: Boolean(player.isAFK),
      status: 'online',
      avatarUrl: player.avatarUrl || buildAvatarUrl(player.uuid, 64),
    });
  }

  for (const player of result.leftPlayers) {
    await publishRealtimeEvent('player_leave', {
      uuid: player.uuid || '',
      username: player.name || '',
      status: 'offline',
      avatarUrl: player.avatarUrl || buildAvatarUrl(player.uuid, 64),
    });
  }

  for (const player of result.snapshot.playerList || []) {
    await publishRealtimeEvent('player_update', {
      uuid: player.uuid || '',
      username: player.name || '',
      playtime: Number(player.totalPlaytime || 0),
      ping: Number(player.ping || 0),
      isAFK: Boolean(player.isAFK),
      status: String(player.status || 'online').toLowerCase(),
      avatarUrl: player.avatarUrl || buildAvatarUrl(player.uuid, 64),
      sessionTime: Number(player.sessionTime || 0),
      dailyPlaytime: Number(player.dailyPlaytime || 0),
      weeklyPlaytime: Number(player.weeklyPlaytime || 0),
      lastUpdate: Number(result.snapshot.lastUpdate || result.timestamp),
    });
  }
}

module.exports = async (req, res) => {
  setCorsHeaders(res);

  if (req.method === 'OPTIONS') {
    return res.status(204).end();
  }

  if (req.method === 'GET') {
    const data = await currentData();
    return res.status(200).json({
      success: true,
      data,
    });
  }

  if (req.method === 'POST') {
    try {
      const body = typeof req.body === 'string' ? JSON.parse(req.body || '{}') : (req.body || {});
      const normalizedPayload = normalizePayload(body);
      await storeSnapshot(normalizedPayload);
      const data = await currentData();

      return res.status(200).json({
        success: true,
        data,
      });
    } catch (error) {
      return res.status(400).json({
        success: false,
        error: 'Invalid JSON payload',
      });
    }
  }

  res.setHeader('Allow', 'GET,POST,OPTIONS');
  return res.status(405).json({
    success: false,
    error: 'Method not allowed',
  });
};

const {
  AFK_TIMEOUT_MS,
  HISTORY_LIMIT,
  applyActiveDelta,
  attachLiveCounters,
  ensurePlayerRecord,
  normalizePlayerId,
  nowMs,
  readState,
  getCachedIdentity,
  setCachedIdentity,
  buildAvatarUrl,
  buildCrackedAvatarUrl,
  buildFallbackAvatarUrl,
  normalizeUuid,
  toFiniteNumber,
  withState,
} = require('./_state');
const { publishRealtimeEvent } = require('./_realtime');

const MOJANG_PROFILE_URL = 'https://api.mojang.com/users/profiles/minecraft/';
const MOJANG_RETRY_COOLDOWN_MS = 24 * 60 * 60 * 1000;
const MOJANG_ERROR_BACKOFF_MS = 10 * 60 * 1000;
const mojangRequestCache = new Map();

const defaultSnapshot = {
  cpu: 0,
  ram: 0,
  ramUsed: 0,
  ramMax: 0,
  players: 0,
  playerList: [],
  uptime: 0,
  ip: 'dxir.live',
  status: 'offline',
  time: '--',
  lastUpdate: 0,
  ready: false,
};

function setCorsHeaders(res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,POST,OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  res.setHeader('Cache-Control', 'no-store, max-age=0');
}

function normalizeStatus(value) {
  return String(value || 'offline').trim().toLowerCase() === 'online' ? 'online' : 'offline';
}

function normalizeNumber(value, fallback = 0) {
  const parsed = toFiniteNumber(value, fallback);
  return parsed >= 0 ? parsed : fallback;
}

async function resolveUuidFromMojang(username) {
  const key = String(username || '').trim().toLowerCase();
  if (!key) {
    return '';
  }

  if (mojangRequestCache.has(key)) {
    return mojangRequestCache.get(key);
  }

  const pending = (async () => {
    const response = await fetch(`${MOJANG_PROFILE_URL}${encodeURIComponent(key)}`, {
      method: 'GET',
      headers: {
        Accept: 'application/json',
      },
    });

    if (response.status === 404 || response.status === 204) {
      return { status: 'missing', uuid: '' };
    }

    if (!response.ok) {
      return { status: 'error', uuid: '' };
    }

    const payload = await response.json();
    const uuid = normalizeUuid(payload?.id);
    return uuid
      ? { status: 'found', uuid }
      : { status: 'missing', uuid: '' };
  })()
    .catch(() => ({ status: 'error', uuid: '' }))
    .finally(() => {
      mojangRequestCache.delete(key);
    });

  mojangRequestCache.set(key, pending);

  try {
    return await pending;
  } catch (error) {
    return { status: 'error', uuid: '' };
  }
}

function normalizePlayerEntry(value) {
  if (typeof value === 'string') {
    const name = value.trim();
    if (!name) {
      return null;
    }

    return { name, uuid: '', ping: 0, status: 'online' };
  }

  if (!value || typeof value !== 'object') {
    return null;
  }

  const name = String(value.name || value.player || value.username || '').trim();
  const uuid = normalizeUuid(value.uuid || value.id || value.playerUuid);

  if (!name) {
    return null;
  }

  return {
    name,
    uuid,
    ping: normalizeNumber(value.ping ?? value.latency ?? value.ms, 0),
    status: String(value.status || 'online').trim() || 'online',
    lastActive: normalizeNumber(value.lastActive ?? value.activityAt, 0),
    active: Boolean(value.active),
  };
}

function normalizePlayerList(value) {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.map(normalizePlayerEntry).filter(Boolean).slice(0, 32);
}

function normalizePayload(payload = {}) {
  const ramUsed = normalizeNumber(payload.ramUsed, defaultSnapshot.ramUsed);

  return {
    cpu: normalizeNumber(payload.cpu, defaultSnapshot.cpu),
    ram: normalizeNumber(payload.ram, Math.round(ramUsed * 1024)),
    ramUsed,
    ramMax: normalizeNumber(payload.ramMax, defaultSnapshot.ramMax),
    players: normalizeNumber(payload.players, defaultSnapshot.players),
    playerList: normalizePlayerList(payload.playerList),
    uptime: normalizeNumber(payload.uptime, defaultSnapshot.uptime),
    ip: typeof payload.ip === 'string' && payload.ip.trim() ? payload.ip.trim() : defaultSnapshot.ip,
    status: normalizeStatus(payload.status),
    time: typeof payload.time === 'string' && payload.time.trim() ? payload.time.trim() : defaultSnapshot.time,
    ready: true,
  };
}

async function resolvePlayersWithMojangUuid(players, sharedState) {
  if (!Array.isArray(players) || !players.length) {
    return [];
  }

  const resolvedPlayers = await Promise.all(players.map(async (player) => {
    const name = String(player?.name || '').trim();
    if (!name) {
      return player;
    }

    const cachedIdentity = getCachedIdentity(sharedState, name);
    const cachedUuid = normalizeUuid(cachedIdentity?.uuid);
    const now = nowMs();

    let mojangUuid = cachedUuid;
    let cachedAvatar = String(cachedIdentity?.avatarUrl || '').trim();

    const canRetryMojang = !cachedIdentity
      || now >= Number(cachedIdentity.nextMojangRetryAt || 0)
      || (!cachedUuid && String(cachedIdentity.mojangStatus || '') === 'unknown');

    if (!mojangUuid && canRetryMojang) {
      const mojangResult = await resolveUuidFromMojang(name);

      if (mojangResult.status === 'found' && mojangResult.uuid) {
        mojangUuid = mojangResult.uuid;
        cachedAvatar = buildAvatarUrl(mojangUuid, 64);
        setCachedIdentity(sharedState, name, {
          uuid: mojangUuid,
          avatarUrl: cachedAvatar,
          mojangStatus: 'found',
          mojangCheckedAt: now,
          nextMojangRetryAt: 0,
          updatedAt: now,
        });
      } else {
        const fallbackAvatar = buildCrackedAvatarUrl(name) || buildFallbackAvatarUrl(name, 64);
        cachedAvatar = fallbackAvatar;
        setCachedIdentity(sharedState, name, {
          uuid: '',
          avatarUrl: fallbackAvatar,
          mojangStatus: mojangResult.status,
          mojangCheckedAt: now,
          nextMojangRetryAt:
            mojangResult.status === 'missing'
              ? now + MOJANG_RETRY_COOLDOWN_MS
              : now + MOJANG_ERROR_BACKOFF_MS,
          updatedAt: now,
        });
      }
    }

    const finalUuid = mojangUuid;
    const avatarUrl = finalUuid
      ? buildAvatarUrl(finalUuid, 64)
      : (cachedAvatar || buildCrackedAvatarUrl(name) || buildFallbackAvatarUrl(name, 64));

    // Debug mapping to verify live UUID source.
    console.log(`[DXIR UUID] ${name} => ${finalUuid || 'missing'}`);

    return {
      ...player,
      uuid: finalUuid,
      avatarUrl,
    };
  }));

  return resolvedPlayers;
}

function cloneSnapshot(snapshot) {
  return {
    ...snapshot,
    playerList: Array.isArray(snapshot.playerList)
      ? snapshot.playerList.map((player) => ({
          name: String(player?.name || '').trim(),
          uuid: String(player?.uuid || player?.id || '').trim(),
          avatarUrl: String(player?.avatarUrl || buildAvatarUrl(player?.uuid, 64) || '').trim(),
          ping: normalizeNumber(player?.ping, 0),
          status: String(player?.status || 'online').trim() || 'online',
          isAFK: Boolean(player?.isAFK),
          sessionTime: normalizeNumber(player?.sessionTime, 0),
          totalPlaytime: normalizeNumber(player?.totalPlaytime, 0),
          dailyPlaytime: normalizeNumber(player?.dailyPlaytime, 0),
          weeklyPlaytime: normalizeNumber(player?.weeklyPlaytime, 0),
        })).filter((player) => Boolean(player.name))
      : [],
  };
}

function enrichPlayersWithStats(players, records, timestamp) {
  return players.map((player) => {
    const id = normalizePlayerId(player);
    const record = id ? records[id] : null;

    if (!record) {
      return {
        ...player,
        isAFK: false,
        sessionTime: 0,
        totalPlaytime: 0,
        dailyPlaytime: 0,
        weeklyPlaytime: 0,
      };
    }

    const counters = attachLiveCounters(record, timestamp);
    return {
      ...player,
      isAFK: Boolean(record.isAFK),
      sessionTime: counters.sessionTime,
      totalPlaytime: counters.totalPlaytime,
      dailyPlaytime: counters.dailyPlaytime,
      weeklyPlaytime: counters.weeklyPlaytime,
    };
  });
}

async function currentData() {
  const state = await readState();
  const timestamp = nowMs();
  const latest = state.latestSnapshot
    ? cloneSnapshot({
        ...state.latestSnapshot,
        playerList: enrichPlayersWithStats(state.latestSnapshot.playerList || [], state.players || {}, timestamp),
      })
    : { ...defaultSnapshot };

  return {
    latest,
    history: Array.isArray(state.history) ? state.history.map(cloneSnapshot) : [],
  };
}

function markOfflinePlayers(playersState, onlineIds, timestamp) {
  Object.values(playersState).forEach((record) => {
    if (!record || !record.id) {
      return;
    }

    if (!onlineIds.has(record.id) && record.isOnline) {
      applyActiveDelta(record, timestamp);
      record.totalPlaytime += record.sessionActiveSeconds;
      record.sessionActiveSeconds = 0;
      record.isOnline = false;
      record.isAFK = false;
      record.joinTime = 0;
      record.lastCalcAt = 0;
      record.ping = 0;
      record.updatedAt = timestamp;
    }
  });
}

function updatePlayerRecords(playersState, players, timestamp) {
  const onlineIds = new Set();

  players.forEach((player) => {
    const record = ensurePlayerRecord(playersState, player, timestamp);

    if (!record) {
      return;
    }

    const id = record.id;
    onlineIds.add(id);

    if (!record.isOnline) {
      record.isOnline = true;
      record.isAFK = false;
      record.joinTime = timestamp;
      record.sessionActiveSeconds = 0;
      record.lastCalcAt = timestamp;
      record.lastActive = player.lastActive > 0 ? player.lastActive : timestamp;
    } else {
      applyActiveDelta(record, timestamp);
    }

    const signaledActivity = player.active || player.lastActive > 0;
    if (signaledActivity) {
      record.lastActive = player.lastActive > 0 ? player.lastActive : timestamp;
      record.isAFK = false;
      record.lastCalcAt = timestamp;
    }

    if (timestamp - record.lastActive >= AFK_TIMEOUT_MS) {
      record.isAFK = true;
    }

    record.uuid = player.uuid || record.uuid;
    record.name = player.name || record.name;
    record.avatarUrl = player.avatarUrl || record.avatarUrl || buildAvatarUrl(player.uuid, 64);
    record.ping = normalizeNumber(player.ping, 0);
    record.lastSeen = timestamp;
    record.updatedAt = timestamp;
  });

  markOfflinePlayers(playersState, onlineIds, timestamp);

  return players.map((player) => {
    const record = playersState[normalizePlayerId(player)];
    if (!record) {
      return player;
    }

    const counters = attachLiveCounters(record, timestamp);
    return {
      ...player,
        avatarUrl: record.avatarUrl || player.avatarUrl || buildAvatarUrl(record.uuid, 64),
      status: record.isOnline ? 'online' : 'offline',
      isAFK: Boolean(record.isAFK),
      sessionTime: counters.sessionTime,
      totalPlaytime: counters.totalPlaytime,
      dailyPlaytime: counters.dailyPlaytime,
      weeklyPlaytime: counters.weeklyPlaytime,
    };
  });
}

async function storeSnapshot(snapshot) {
  const { result } = await withState(async (state) => {
    const timestamp = nowMs();
    const previousPlayers = Array.isArray(state.latestSnapshot?.playerList) ? state.latestSnapshot.playerList : [];
    const previousOnline = new Map(previousPlayers.map((player) => [normalizePlayerId(player), player]));
    const resolvedPlayerList = await resolvePlayersWithMojangUuid(snapshot.playerList || [], state);
    const updatedPlayers = updatePlayerRecords(state.players, resolvedPlayerList, timestamp);
    const stampedSnapshot = {
      ...snapshot,
      playerList: updatedPlayers,
      lastUpdate: timestamp,
    };

    state.latestSnapshot = stampedSnapshot;
    state.history = [...(Array.isArray(state.history) ? state.history : []), stampedSnapshot].slice(-HISTORY_LIMIT);

    const currentOnline = new Map(
      updatedPlayers
        .filter((player) => String(player.status || '').toLowerCase() !== 'offline')
        .map((player) => [normalizePlayerId(player), player])
    );

    const joinedPlayers = [];
    const leftPlayers = [];

    currentOnline.forEach((player, id) => {
      if (!previousOnline.has(id)) {
        joinedPlayers.push(player);
      }
    });

    previousOnline.forEach((player, id) => {
      if (!currentOnline.has(id)) {
        leftPlayers.push(player);
      }
    });

    const playtimeRows = Object.values(state.players || {})
      .map((record) => {
        if (!record || !record.id) {
          return null;
        }

        const counters = attachLiveCounters(record, timestamp);
        return {
          username: record.name || record.uuid || record.id,
          uuid: record.uuid || '',
          value: counters.totalPlaytime,
        };
      })
      .filter(Boolean)
      .sort((a, b) => b.value - a.value)
      .slice(0, 10);

    if (!state.leaderboards || typeof state.leaderboards !== 'object') {
      state.leaderboards = {};
    }

    state.leaderboards.playtime = {
      items: playtimeRows,
      updatedAt: timestamp,
    };

    return {
      snapshot: stampedSnapshot,
      joinedPlayers,
      leftPlayers,
      playtimeRows,
      timestamp,
    };
  });

  if (!result) {
    return;
  }

  await publishRealtimeEvent('stats_update', {
    latest: result.snapshot,
  });

  await publishRealtimeEvent('leaderboard_update', {
    category: 'playtime',
    updatedAt: result.timestamp,
    items: result.playtimeRows,
  });

  for (const player of result.joinedPlayers) {
    await publishRealtimeEvent('player_join', {
      uuid: player.uuid || '',
      username: player.name || '',
      playtime: Number(player.totalPlaytime || 0),
      ping: Number(player.ping || 0),
      isAFK: Boolean(player.isAFK),
      status: 'online',
      avatarUrl: player.avatarUrl || buildAvatarUrl(player.uuid, 64),
    });
  }

  for (const player of result.leftPlayers) {
    await publishRealtimeEvent('player_leave', {
      uuid: player.uuid || '',
      username: player.name || '',
      status: 'offline',
      avatarUrl: player.avatarUrl || buildAvatarUrl(player.uuid, 64),
    });
  }

  for (const player of result.snapshot.playerList || []) {
    await publishRealtimeEvent('player_update', {
      uuid: player.uuid || '',
      username: player.name || '',
      playtime: Number(player.totalPlaytime || 0),
      ping: Number(player.ping || 0),
      isAFK: Boolean(player.isAFK),
      status: String(player.status || 'online').toLowerCase(),
      avatarUrl: player.avatarUrl || buildAvatarUrl(player.uuid, 64),
      sessionTime: Number(player.sessionTime || 0),
      dailyPlaytime: Number(player.dailyPlaytime || 0),
      weeklyPlaytime: Number(player.weeklyPlaytime || 0),
      lastUpdate: Number(result.snapshot.lastUpdate || result.timestamp),
    });
  }
}

module.exports = async (req, res) => {
  setCorsHeaders(res);

  if (req.method === 'OPTIONS') {
    return res.status(204).end();
  }

  if (req.method === 'GET') {
    const data = await currentData();
    return res.status(200).json({
      success: true,
      data,
    });
  }

  if (req.method === 'POST') {
    try {
      const body = typeof req.body === 'string' ? JSON.parse(req.body || '{}') : (req.body || {});
      const normalizedPayload = normalizePayload(body);
      await storeSnapshot(normalizedPayload);
      const data = await currentData();

      return res.status(200).json({
        success: true,
        data,
      });
    } catch (error) {
      return res.status(400).json({
        success: false,
        error: 'Invalid JSON payload',
      });
    }
  }

  res.setHeader('Allow', 'GET,POST,OPTIONS');
  return res.status(405).json({
    success: false,
    error: 'Method not allowed',
  });
};

const {
  LEADERBOARD_LIMIT,
  normalizeLeaderboardItems,
  nowMs,
  readState,
  withState,
  getCachedIdentity,
  normalizeUuid,
  buildAvatarUrl,
} = require('./_state');
const { publishRealtimeEvent } = require('./_realtime');

const API_TO_STORE_KEY = {
  topKills: 'kills',
  richest: 'balance',
  bounty: 'bounty',
  earnings: 'earnings',
  playtime: 'playtime',
};

const HISTORY_KEYS = Object.keys(API_TO_STORE_KEY);

function setCorsHeaders(res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,POST,OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  res.setHeader('Cache-Control', 'no-store, max-age=0');
}

function hydrateRows(sourceState, rows) {
  return rows.map((entry) => {
    const username = String(entry?.username || '').trim();
    const cached = getCachedIdentity(sourceState, username);
    const uuid = normalizeUuid(entry?.uuid) || normalizeUuid(cached?.uuid);
    return {
      ...entry,
      uuid,
      avatarUrl: buildAvatarUrl(uuid, 64),
    };
  });
}

function cloneState(source) {
  return HISTORY_KEYS.reduce((acc, key) => {
    const storeKey = API_TO_STORE_KEY[key];
    const rows = source?.leaderboards?.[storeKey]?.items;
    acc[key] = Array.isArray(rows) ? hydrateRows(source, rows) : [];
    return acc;
  }, {});
}

function extractRows(body, key) {
  if (!body || typeof body !== 'object') {
    return [];
  }

  const source = body[key];
  if (Array.isArray(source)) {
    return source;
  }

  if (source && typeof source === 'object') {
    return source.items || source.data || source.entries || source.rows || [];
  }

  return [];
}

function toTimestampMap(source) {
  return HISTORY_KEYS.reduce((acc, key) => {
    const storeKey = API_TO_STORE_KEY[key];
    acc[key] = Number(source?.leaderboards?.[storeKey]?.updatedAt || 0);
    return acc;
  }, {});
}

function mergePayload(body = {}, sourceState) {
  const nextState = cloneState(sourceState);

  HISTORY_KEYS.forEach((key) => {
    const rows = extractRows(body, key);
    if (rows.length) {
      nextState[key] = normalizeLeaderboardItems(rows).slice(0, LEADERBOARD_LIMIT);
    }
  });

  return nextState;
}

module.exports = async (req, res) => {
  setCorsHeaders(res);

  if (req.method === 'OPTIONS') {
    return res.status(204).end();
  }

  if (req.method === 'GET') {
    const state = await readState();
    return res.status(200).json({
      ...cloneState(state),
      updatedAt: toTimestampMap(state),
    });
  }

  if (req.method === 'POST') {
    try {
      const body = typeof req.body === 'string' ? JSON.parse(req.body || '{}') : (req.body || {});
      const hasLeaderboardKeys = HISTORY_KEYS.some((key) => Object.prototype.hasOwnProperty.call(body, key));

      if (!hasLeaderboardKeys) {
        const state = await readState();
        return res.status(200).json({
          ...cloneState(state),
          updatedAt: toTimestampMap(state),
        });
      }

      const timestamp = nowMs();

      const { state } = await withState((draft) => {
        const merged = mergePayload(body, draft);

        HISTORY_KEYS.forEach((key) => {
          const storeKey = API_TO_STORE_KEY[key];
          if (!Array.isArray(merged[key])) {
            return;
          }

          draft.leaderboards[storeKey] = {
            items: merged[key],
            updatedAt: timestamp,
          };
        });
      });

      const responsePayload = {
        ...cloneState(state),
        updatedAt: toTimestampMap(state),
      };

      await Promise.all(
        HISTORY_KEYS
          .filter((key) => Object.prototype.hasOwnProperty.call(body, key))
          .map((key) => publishRealtimeEvent('leaderboard_update', {
            category: API_TO_STORE_KEY[key],
            updatedAt: Number(responsePayload.updatedAt?.[key] || timestamp),
            items: Array.isArray(responsePayload[key]) ? responsePayload[key] : [],
          }))
      );

      return res.status(200).json(responsePayload);
    } catch (error) {
      return res.status(400).json({
        error: 'Invalid JSON payload',
      });
    }
  }

  res.setHeader('Allow', 'GET,POST,OPTIONS');
  return res.status(405).json({
    error: 'Method not allowed',
  });
};

