      <span class="leaderboard-loading__rank"></span>
      <span class="leaderboard-loading__avatar"></span>
      <span class="leaderboard-loading__text"></span>
      <span class="leaderboard-loading__value"></span>
    `;
    fragment.appendChild(row);
